/* ── util hooks ─────────────────────────────────────── */
function useOnScreen(threshold = 0.12) {
  const ref = useRef(null)
  const [on, setOn] = useState(false)
  useEffect(() => {
    const el = ref.current; if (!el) return
    const ob = new IntersectionObserver(([e]) => { if (e.isIntersecting) { setOn(true); ob.disconnect() } }, { threshold })
    ob.observe(el)
    return () => ob.disconnect()
  }, [threshold])
  return [ref, on]
}

function useCount(target, running) {
  const [n, setN] = useState(0)
  useEffect(() => {
    if (!running) return
    let s = null
    const raf = ts => { if (!s) s = ts; const p = Math.min((ts - s) / 2000, 1); setN(Math.round(p * target)); if (p < 1) requestAnimationFrame(raf) }
    requestAnimationFrame(raf)
  }, [target, running])
  return n
}

